1	interface QuoteItem {
2	  type: string;
3	  cursed?: boolean;
4	}
5	
6	interface QuoteStep {
7	  op: "quote";
8	  items: QuoteItem[];
9	}
10	
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  amulet: 60,
18	  sword: 100,
19	};
20	
21	const FIRST_INSURANCE_RATE = 0.1;
22	const PROCESSING_FEE = 5;
23	
24	const CURSE_SURCHARGE_RATE = 0.5;
25	
26	function itemBasePremium(item: QuoteItem): number {
27	  return BASE_PREMIUM[item.type] ?? 0;
28	}
29	
30	function itemSurcharges(item: QuoteItem): number {
31	  const base = itemBasePremium(item);
32	  return item.cursed ? base * CURSE_SURCHARGE_RATE : 0;
33	}
34	
35	function priceQuoteStep(step: QuoteStep): { premium: number } {
36	  const policyBase = step.items.reduce(
37	    (sum, item) => sum + itemBasePremium(item),
38	    0,
39	  );
40	  const itemSurchargeTotal = step.items.reduce(
41	    (sum, item) => sum + itemSurcharges(item),
42	    0,
43	  );
44	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
45	  const premium = Math.ceil(
46	    policyBase + itemSurchargeTotal + firstInsurance + PROCESSING_FEE,
47	  );
48	  return { premium };
49	}
50	
51	export function runScenario(scenario: Scenario): {
52	  results: { premium: number }[];
53	} {
54	  const results = scenario.steps.map(priceQuoteStep);
55	  return { results };
56	}
